/* ================================================================
 * SUIT Variable 폰트 — CDN @import
 *
 * 별도 파일로 분리한 이유:
 * CSS 스펙상 @import는 다른 모든 rule보다 앞에 와야 한다.
 * typography.css 안에 두면 typography.css가 다른 파일 다음에 import될 때
 * @import가 중간에 끼어 파서가 오류로 처리한다.
 *
 * 따라서 이 파일은 사용자 앱의 entry CSS 최상단에 가장 먼저 import한다:
 *   @import '@transight-design/ui/styles/font-suit.css';
 *   @import 'tailwindcss';
 *   ...
 * ================================================================ */

@import url('https://cdn.jsdelivr.net/gh/sunn-us/SUIT/fonts/variable/woff2/SUIT-Variable.css');
